import{_ as i,c as a,o,a1 as l}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"Платформы и интеграции: Конфигурация многомодельного ИИ | oh-my-opencode","description":"Научитесь настраивать и управлять несколькими ИИ-платформами (Anthropic, OpenAI, Google, Copilot), осваивайте механизм автоматического понижения и интеллектуальный выбор моделей.","frontmatter":{"title":"Платформы и интеграции: Конфигурация многомодельного ИИ | oh-my-opencode","sidebarTitle":"Подключение ваших учётных записей ИИ","subtitle":"Платформы и интеграции: Конфигурация многомодельного ИИ","description":"Научитесь настраивать и управлять несколькими ИИ-платформами (Anthropic, OpenAI, Google, Copilot), осваивайте механизм автоматического понижения и интеллектуальный выбор моделей.","order":40},"headers":[],"relativePath":"ru/code-yeongyu/oh-my-opencode/platforms/index.md","filePath":"ru/code-yeongyu/oh-my-opencode/platforms/index.md"}'),r={name:"ru/code-yeongyu/oh-my-opencode/platforms/index.md"};function s(t,e,n,d,p,h){return o(),a("div",null,[...e[0]||(e[0]=[l(`<h1 id="платформы-и-интеграции" tabindex="-1">Платформы и интеграции <a class="header-anchor" href="#платформы-и-интеграции" aria-label="Permalink to &quot;Платформы и интеграции&quot;">​</a></h1><p>В этой главе описывается, как настроить и управлять несколькими AI Provider (Anthropic, OpenAI, Google, GitHub Copilot и др.), а также механизм автоматического понижения моделей в oh-my-opencode.</p><p>Изучив эту главу, вы научитесь позволять системе интеллектуально выбирать наиболее подходящую AI-модель в зависимости от типа задачи и доступных моделей, создавая эффективный и надёжный рабочий процесс многомодельной оркестрации.</p><h2 id="что-включает-эта-глава" tabindex="-1">Что включает эта глава <a class="header-anchor" href="#что-включает-эта-глава" aria-label="Permalink to &quot;Что включает эта глава&quot;">​</a></h2><p>Эта глава состоит из двух частей:</p><h3 id="_1-настроика-provider" tabindex="-1">1. <a href="./provider-setup/">Настройка Provider</a> <a class="header-anchor" href="#_1-настроика-provider" aria-label="Permalink to &quot;1. [Настройка Provider](provider-setup/)&quot;">​</a></h3><p>Научитесь настраивать различные AI Provider, включая:</p><ul><li>Anthropic Claude (основной выбор для оркестратора)</li><li>OpenAI ChatGPT (специально для архитектурного анализа)</li><li>Google Gemini (для фронтенда и медиа-анализа)</li><li>GitHub Copilot (резервный Provider)</li><li>Z.ai Coding Plan и OpenCode Zen (дополнительные сервисы)</li></ul><p><strong>Что вы сможете сделать после изучения</strong>:</p><ul><li>✅ Настроить 6 основных AI Provider</li><li>✅ Использовать интерактивный установщик для быстрой настройки</li><li>✅ Назначить наиболее подходящие модели для разных агентов</li><li>✅ Использовать команду <code>doctor</code> для диагностики проблем конфигурации</li></ul><p><strong>Примерное время</strong>: 25-30 минут</p><h3 id="_2-стратегия-многомодельности" tabindex="-1">2. <a href="./model-resolution/">Стратегия многомодельности</a> <a class="header-anchor" href="#_2-стратегия-многомодельности" aria-label="Permalink to &quot;2. [Стратегия многомодельности](model-resolution/)&quot;">​</a></h3><p>Глубоко разберитесь с трёхступенчатым механизмом приоритетов системы разрешения моделей:</p><ul><li>Пользовательское переопределение (точный контроль)</li><li>Понижение Provider (автоматическая отказоустойчивость)</li><li>Системные значения по умолчанию (резервный вариант)</li></ul><p><strong>Что вы сможете сделать после изучения</strong>:</p><ul><li>✅ Понять полный рабочий процесс разрешения моделей</li><li>✅ Вручную указывать модели в зависимости от требований задачи</li><li>✅ Использовать понижение Provider для повышения отказоустойчивости системы</li><li>✅ Диагностировать и решать проблемы разрешения моделей</li></ul><p><strong>Примерное время</strong>: 30-35 минут</p><h2 id="рекомендации-по-порядку-обучения" tabindex="-1">Рекомендации по порядку обучения <a class="header-anchor" href="#рекомендации-по-порядку-обучения" aria-label="Permalink to &quot;Рекомендации по порядку обучения&quot;">​</a></h2><p>Мы рекомендуем изучать эту главу в следующем порядке:</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[Установка и настройка завершены] --&gt; B[Настройка Provider]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; C[Стратегия многомодельности]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; D[Расширенные функции]</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style A fill:#e0f2fe</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style B fill:#dbeafe</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style C fill:#bfdbfe</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style D fill:#93c5fd</span></span></code></pre></div><p><strong>Почему именно этот порядок?</strong></p><ol><li><strong>Сначала настройка, затем понимание</strong>: Сначала научитесь настраивать различные Provider, затем разберитесь с механизмом разрешения, лежащим в основе</li><li><strong>От простого к сложному</strong>: Настройка Provider — это базовая операция, стратегия многомодельности — это расширенная концепция</li><li><strong>Практика подтверждает теорию</strong>: После настройки Provider вы можете использовать команду <code>doctor</code> для проверки эффективности стратегии многомодельности</li></ol><div class="tip custom-block"><p class="custom-block-title">Быстрый путь для начинающих</p><p>Если вы хотите быстро начать работу, сначала выполните шаги 1-4 в разделе <a href="./provider-setup/">Настройка Provider</a> (настройка базовых Provider), остальное можно изучить позже по мере необходимости.</p></div><h2 id="предварительные-условия" tabindex="-1">Предварительные условия <a class="header-anchor" href="#предварительные-условия" aria-label="Permalink to &quot;Предварительные условия&quot;">​</a></h2><p>Перед изучением этой главы убедитесь, что:</p><ul><li>✅ Выполнена <a href="./../installation/">установка и начальная настройка</a></li><li>✅ Установлен OpenCode (версия &gt;= 1.0.150)</li><li>✅ Вы понимаете базовый формат файлов конфигурации JSON/JSONC</li><li>✅ У вас есть подписка хотя бы на один AI Provider (рекомендуется Anthropic Claude)</li></ul><div class="warning custom-block"><p class="custom-block-title">Что делать, если нет учётной записи Provider?</p><p>Вы можете сначала изучить шаги настройки, но не подключать Provider. Система будет использовать модель по умолчанию от OpenCode как резервный вариант.</p></div><h2 id="часто-задаваемые-вопросы" tabindex="-1">Часто задаваемые вопросы <a class="header-anchor" href="#часто-задаваемые-вопросы" aria-label="Permalink to &quot;Часто задаваемые вопросы&quot;">​</a></h2><details><summary><strong>Нужно ли настраивать все Provider?</strong></summary><p>Нет. Вы можете настроить только наиболее часто используемый Provider (например, только Anthropic Claude). Механизм понижения Provider в oh-my-opencode автоматически будет использовать доступные Provider.</p><p>Однако если вы хотите в полной мере воспользоваться преимуществами многомодельной оркестрации, рекомендуется настроить хотя бы 2-3 Provider, чтобы система могла автоматически выбирать наиболее подходящую модель в зависимости от типа задачи.</p></details><details><summary><strong>В чём разница между настройкой Provider и разрешением моделей?</strong></summary><ul><li><strong>Настройка Provider</strong>: это &quot;шаг установки&quot;, сообщает системе, какие AI-сервисы у вас доступны</li><li><strong>Разрешение моделей</strong>: это &quot;логика принятия решений&quot;, как система выбирает, какой Provider использовать для каждого агента</li></ul><p>Аналогия: настройка Provider — это &quot;найм членов команды&quot;, разрешение моделей — это &quot;распределение задач&quot;.</p></details><details><summary><strong>Можно ли вносить изменения в конфигурацию в любое время?</strong></summary><p>Вы можете вносить изменения в файл конфигурации в любое время:</p><ul><li>Пользовательская конфигурация: <code>~/.config/opencode/oh-my-opencode.json</code></li><li>Конфигурация проекта: <code>.opencode/oh-my-opencode.json</code></li></ul><p>После внесения изменений перезапуск не требуется, изменения вступят в силу при следующем использовании агента. Если вы изменили аутентификацию Provider, необходимо выполнить <code>opencode auth login</code> для повторной аутентификации.</p></details><h2 id="следующие-шаги" tabindex="-1">Следующие шаги <a class="header-anchor" href="#следующие-шаги" aria-label="Permalink to &quot;Следующие шаги&quot;">​</a></h2><p>После завершения этой главы вы можете:</p><h3 id="рекомендуемыи-путь-изучение-команды-ai-агентов" tabindex="-1">Рекомендуемый путь: изучение команды AI-агентов <a class="header-anchor" href="#рекомендуемыи-путь-изучение-команды-ai-агентов" aria-label="Permalink to &quot;Рекомендуемый путь: изучение команды AI-агентов&quot;">​</a></h3><p>Продолжайте изучение <a href="./../../advanced/ai-agents-overview/">Команда AI-агентов: обзор 10 экспертов</a>, чтобы узнать, как использовать разных агентов для выполнения профессиональных задач.</p><h3 id="расширенныи-путь-глубокая-настроика-конфигурации" tabindex="-1">Расширенный путь: глубокая настройка конфигурации <a class="header-anchor" href="#расширенныи-путь-глубокая-настроика-конфигурации" aria-label="Permalink to &quot;Расширенный путь: глубокая настройка конфигурации&quot;">​</a></h3><p>Если вы уже знакомы с базовой настройкой, переходите к <a href="./../../advanced/advanced-configuration/">Глубокая настройка конфигурации: агенты и управление разрешениями</a>, чтобы изучить:</p><ul><li>Как настроить подсказки агентов</li><li>Как настроить разрешения и область доступа агентов</li><li>Как создавать пользовательские агенты и категории</li></ul><h3 id="практическии-путь-использование-планирования-prometheus" tabindex="-1">Практический путь: использование планирования Prometheus <a class="header-anchor" href="#практическии-путь-использование-планирования-prometheus" aria-label="Permalink to &quot;Практический путь: использование планирования Prometheus&quot;">​</a></h3><p>Начните использовать <a href="./../../advanced/prometheus-planning/">Планирование Prometheus: сбор требований в формате интервью</a>, чтобы на практике ощутить мощь многомодельной оркестрации через взаимодействие агентов.</p><hr><p><strong>Начните обучение</strong>: Начните своё путешествие в многомодельной оркестрации с <a href="./provider-setup/">Настройки Provider</a>!</p>`,42)])])}const m=i(r,[["render",s]]);export{u as __pageData,m as default};
